Part.Source:
For Each Order EmpCod, FilCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	&FilFan = FilFan
	&FilCodRazSugg = FilCodRazSugg
	Exit
EndFor

&Periodo = 'Data Emissão:'
MB 4
MT 2

Header
	&titulo = 'NOTAS FISCAIS DE SERVIÇO EMITIDAS NO PERÍODO'

	print Cabecalho
End

if &Tipo = 'P' or &Tipo = 'S' // Propria ou Todas
	&IsImprimeCabecalho = true

	For Each  Order EmpCod, NfsFilCod,NfsProTer, NfsDtaEms,NfsNum, NfsCod
		Where EmpCod = &EmpCod
		Where NfsFilCod = &FilCod
		Where (NfsDtaEms >= &NFsDtaEms and NfsDtaEms <= &NFsDtaEms_to) 
		Where NfsProTer = Nota_ProPriaTerceira.PROPRIA
		Where NfsCliCod = &auxNFsCliCod When &auxNFsCliCod <> 0 
		Where NfsCNAE = &NfsCNAe When &NfsCNAe <> ''
		Where NfsSts <> Status_NFe.Inutilizada

		&StatusVermelho = ''
		&StatusAzul = ''
		&StatusPreto = ''
		&StatusLaranja = ''
		Do case
			CAse NfsSts = Status_NFe.Cancelada
				&QtdCancelada += 1
				&StatusVermelho = 'CAN.'
			Case NfsSts = Status_NFe.Denegada
				&QtdDenegada += 1
				&StatusVermelho = 'DEN.'
			Case NfsSts = Status_NFe.autorizada
				&StatusAzul = 'AUT.'
				&QtdAutorizada += 1	
			Otherwise
				&StatusPreto = 'DIG.'
				&QtdDigitando += 1
		EndCAse

		&AuxNfsDtaEms = NfsDtaEms
		if &IsImprimeCabecalho = true

			&FilCodNom = &FilCodRazSugg
			&IsImprimeCabecalho = false
			print Filtro
			&TipoEmissao = 'EMISSÃO PRÓPRIA - NFS-e'
			print TIpoEmissao
			print cabecalhoNotas
		EndIF

		&SoNumeros = padL(trim(str(NfsNum)), 9, '0')
		&AuxNfsNum = substr(&SoNumeros, 1, 3) +'.' + substr(&SoNumeros, 4, 3) + '.' + substr(&SoNumeros, 7, 3)

		&NfsSts = NfsSts
		&AuxNfsCnae = NfsCNAE		
		&NfsCliCod = NfsCliCod
		&NfsCliRaz = NfsCliRaz

		&NfsPerISS = NfsPerISS
		&NfsTotISS = NfsTotISS
		&NfsTotSer = NfsTotSer 
		&NfsVlrTot = NfsVlrTot

		print Nota

		Do 'TotaisNotas'

		&IsUmaNota = true
	EndFor

	if &IsUmaNota = true
		print TotalNotas
	Endif

	if &QtdDenegada > 0
		Print TotalDenegadas
	EndiF

	if &QtdDigitando > 0
		print TotalDigitando
	EndiF

	If &QtdInutilizada > 0
		print TotalInutilizada
	EndIf

	if &IsUmaNota = true
		print TotaisPorCFOP

		&TotcnaeNfsVlrTot = 0
		&TotCnaeNfsTotISS = 0
		&QtdNotasCnae = 0 
		&CnaeNfsVlrTot = 0
		&CnaeNfsTotISS = 0
		&sdtCnae.Sort('NfsCnae')
		For &sdtCnaeItem in &sdtCnae

			&AuxNfsCnaeDesc = &sdtCnaeItem.NfsCnaeDesc
			&CnaeNfsVlrTot = &sdtCnaeItem.NfsVlrTot
			&CnaeNfsTotISS = &sdtCnaeItem.NfsTotISS			
			&tottAutorizada = &sdtCnaeItem.QtdNotas

			&QtdNotasCnae +=  &sdtCnaeItem.QtdNotas
			&TotcnaeNfsVlrTot +=  &sdtCnaeItem.NfsVlrTot
			&TotCnaeNfsTotISS += &sdtCnaeItem.NfsTotISS

			print ItemCnae
		EndFor

		print TotaisCfo
	Endif

	&IsUmaNota = false
Endif

