Sub 'TotaisNotas'
	Do Case
		Case &NfsSts = Status_NFe.Cancelada			
			&CanceladaNfsVlrTot += &NfsVlrTot
			&CanceladoNfsTotISS += &NfsTotISS

		Case &CteSts = Status_NFe.Inutilizada			
			&InutilizadaNfsVlrTot += &NfsVlrTot

			//		Case &CteSts = Status_NFe.Denegada
			//			&InutilizadaNfsVlrTot += &NfsVlrTot

		Case &CteSts = Status_NFe.Digitando
			&DigitandoNfsVlrTot += &NfsVlrTot

		Otherwise

			&AutorizadaNfsVlrTot += &NfsVlrTot
			&AutorizadaNfsTotISS += &NfsTotISS

			&IsAchou = false
			For &sdtCnaeItem in &sdtCnae
				If  &sdtCnaeItem.NfsCnae = &AuxNfsCnae
					&IsAchou = true					
					&sdtCnaeItem.NfsVlrTot += &NfsVlrTot
					&sdtCnaeItem.NfsTotISS += &NfsTotISS
					&sdtCnaeItem.QtdNotas  += 1
					Exit
				EndIf				
			EndFor

			If &IsAchou = false
				For Each Order EmpCod,CnaeCod
					Where EmpCod = &EmpCod
					Where CnaeCod = &AuxNfsCnae
					&NfsCnaeDesc = CnaeDesc
					Exit
				EndFor

				&sdtCnaeItem = new()
				&sdtCnaeItem.NfsCnae = &AuxNfsCnae
				&sdtCnaeItem.NfsCnaeDesc = &NfsCnaeDesc
				&sdtCnaeItem.NfsVlrTot = &NfsVlrTot
				&sdtCnaeItem.NfsTotISS = &NfsTotISS
				&sdtCnaeItem.QtdNotas  = 1
				&sdtCnae.Add(&sdtCnaeItem)
			EndIf
	EndCase
EndSub
